SELECT ?model ?modelName ?org ?defs WHERE {
  ?model a bboExt:Model .
  FILTER(?model = <https://www.teamingai-project.eu/model/fbb0adafe6924f58ac902063a36646fe> || 
         STR(?model) = "fbb0adafe6924f58ac902063a36646fe" ||
         ?model tai:normalizedId = "fbb0adafe6924f58ac902063a36646fe" ||
         ?model tai:originalId = "fbb0adafe6924f58ac902063a36646fe")
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?defs tai:belongsTo ?model . }
}
LIMIT 25

